import fs from "node:fs";
import path from "node:path";

const contentDir = path.join(process.cwd(), "content/articles");
const outFile = path.join(process.cwd(), "app/articles/loaders.generated.ts");

const slugs = fs.existsSync(contentDir)
  ? fs
      .readdirSync(contentDir)
      .filter((f) => f.endsWith(".mdx"))
      .map((f) => f.replace(/\.mdx$/, ""))
      .sort()
  : [];

const body = [
  "// AUTO-GENERATED by scripts/gen-article-loaders.mjs — do not edit by hand.",
  "// Run `pnpm articles:gen` after adding or removing an article .mdx file.",
  'import type React from "react";',
  "",
  "export const LOADERS: Record<string, () => Promise<{ default: React.ComponentType }>> = {",
  ...slugs.map((s) => `  ${JSON.stringify(s)}: () => import(${JSON.stringify(`@/content/articles/${s}.mdx`)}),`),
  "};",
  "",
].join("\n");

fs.writeFileSync(outFile, body);
console.log(`articles:gen → ${slugs.length} loader(s) written to ${path.relative(process.cwd(), outFile)}`);
